    import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
	import sailpoint.object.AttributeDefinition;
	import sailpoint.object.AttributeSource;
	import sailpoint.object.AttributeTarget;
	import sailpoint.object.Identity;
	import sailpoint.tools.Util;
	import sailpoint.object.Link;

	Log logger = LogFactory.getLog("rule.identityattributetarget.syncInternalId");
	logger.debug("Starting of rule Ascension-Rule-IdentityAttributeTarget-InternalIDs");
  
  String value = identity.getAttribute("internalId");
  logger.debug("identity processed " + identity.getName() + " - Internal Id - " + value);
	
	if(Util.isNotNullOrEmpty(value)) {
		return determineBaseSID(value);
	}
  
	logger.debug("Exiting of rule Ascension-Rule-IdentityAttributeTarget-InternalIDs");
	return value;
